var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"멈추어라, 불 <color=#ff3636>타오르는 어</color>린 양! 침몰<color=#ff3636> 당하는 부모</color>님을 위<b>하</b>여……!","JPN":"止まれ、燃<color=#ff3636>え上がる子</color>羊よ！　沈没<color=#ff3636>する両</color>親のた<b>め</b>に……！","ENG":"Stop, y<color=#ff3636>ou burnin</color>g young lamb! For <color=#ff3636>the sinking</color> par<b>ent</b>s...!","TWN":"止住吧，燃<color=#ff3636>燒的小</color>羊！為衰敗<color=#ff3636>的</color>父<b>母</b>親……！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"다가<color=#ff3636>올 눈부신 멸</color>망을 위해, 괴상<color=#ff3636>망측한 용</color>서를 <b>빌</b> 지어다……!","JPN":"来る<color=#ff3636>べき輝かしい滅</color>亡のために、奇怪<color=#ff3636>な許</color>しを求<b>め</b>よ……！","ENG":"Pray f<color=#ff3636>or absurd</color> forgiveness, for t<color=#ff3636>he dazzling do</color>om to<b> come</b>......!","TWN":"燦<color=#ff3636>爛的末</color>日將到，祈求<color=#ff3636>詭異的</color>饒<b>恕</b> ……！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"휴우, 일단 이걸로 시간은 꽤 벌었을까나?","JPN":"ふう、これで一応時間がを稼げたかな？","ENG":"Phew... That should buy us some time, right?","TWN":"呼，這樣應該可以爭取些時間吧？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"이쪽이야. 자매님. 빨리 안 오면 떼놓고 간다?","JPN":"こっちだよ、シスター。早く来ないと置いていくよ？","ENG":"This way. If you keep falling behind, I'll have to go without you, Sister.","TWN":"這裡！姊妹，你再不過來我要扔下你跑囉！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"왜 그래? 자매님?","JPN":"どうしたの？　シスター。","ENG":"What's wrong? Sister?","TWN":"姊妹？你怎麼了？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저, 아그네스 자매님이라고 하셨죠? 구해 주셔서 감사합니다.","JPN":"あの、アグネスといいましたか？　助けていただきありがとうございます。","ENG":"S-sister Agnes, was it? Thank you for rescuing me.","TWN":"你說你是艾格妮絲姊妹對吧？謝謝你來救我。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런데…… 그 옷차림은?","JPN":"でも……その服は？","ENG":"But... That uniform...","TWN":"不過……你這身打扮是？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"아아, 이거? 로마에 가면 로마 법을 따르라.","JPN":"ああ、これ？　郷に入っては郷に従えってね。","ENG":"Oh, this? \\"When in Rome\\", right?","TWN":"喔喔～這個喔？俗話說要入境隨俗的嘛。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"노출이 좀 많지만, 이 마을에 잠입하려면 얘들 복장 양식을 따라야 하거든.","JPN":"ちょっと露出が高いけど、この村に潜入するためには同じ服装でないとまずいから。","ENG":"It's a little revealing, but I had to adhere to their dress code in order to infiltrate the village.","TWN":"雖然有點暴露，不過要潛入這個村莊，就要先模仿他們的穿著嘛。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"어라? 우리 자매님, 표정이 왜 그럴까?","JPN":"あら？　なんだかうかない表情ね？","ENG":"Hmm? Why the long face, Sister?","TWN":"姊妹？你怎麼這個表情？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"대침식전이 아니라 대인작전을 요청했던 건 유감스럽게 됐어.","JPN":"対侵食戦じゃなくて、対人作戦を要請したのは残念だったわね。","ENG":"I'm sorry for requesting help as an anti-personnel operation, and not as an anti-C.O. one.","TWN":"我很遺憾，請求作戰的對象不是侵蝕體而是人。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"하지만 성황청의 지원이 올 동안 사태가 이렇게 갑자기 악화될 줄은 예상 못했거든.","JPN":"でも聖皇庁の支援が到着する前に、こんなに事態が悪化するとは思わなかったの。","ENG":"However, I didn't expect the situation to suddenly worsen while the Holy Curia's reinforcements were on their way.","TWN":"不過誰都沒想到，在聖皇廳之支援抵達前，情況會突然惡化成這樣。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"악화되었다고요?","JPN":"悪化した？","ENG":"Worsen?","TWN":"惡化？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"뭐, 이런 곳에선 흔해 빠진 얘기야.","JPN":"まあ、こういうところではよくあることだわ。","ENG":"Well, it's rather common around here.","TWN":"這種地方不是常有這種事嗎？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};